const { sendManagerAlert } = require('./app/js/tasks/notificationService.js');
const { purchases } = $input.first().json;
if (purchases.length === 0) return $input.all();
const text = `🧾 Активні закупки (${purchases.length}):\n` + purchases.map(p => `• ${p.purchase_request_id}: ${p.status}`).join('\n');
await sendManagerAlert(text);
return $input.all();

// Input: { purchase_request_id }
// Calls: stockService.addStock() for each item
// Calls: updateRow PurchaseRequests status = Received
// Then re-checks WaitingPurchase orders
const { addStock } = require('./app/js/stock/stockService.js');
const { findRows, updateRow } = require('./app/js/data/rowRepository.js');
const prId = $input.first().json.purchase_request_id;
const items = findRows('PurchaseRequestItems', r => r.purchase_request_id === prId);
for (const item of items) {
  if (item.component_id) addStock(item.component_id, Number(item.quantity || 0), `purchase:${prId}`);
}
updateRow('PurchaseRequests', 'purchase_request_id', prId, { status: 'Received' });
return [{ json: { received: prId, items } }];
